/**
 * Converts a PascalCase model name to kebab-case for use in file names and URL paths.
 * e.g. "UserProfile" → "user-profile"
 */
export function toKebabCase(name: string): string {
  return name.replace(/([A-Z])/g, (match, char: string, offset: number) => (offset > 0 ? '-' : '') + char.toLowerCase())
}

/**
 * Lowercases the first character of a string for camelCase property names.
 * e.g. "User" → "user", "BlogPost" → "blogPost"
 */
export function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

