import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { scalarToTs } from './scalar-map'

function fieldTsType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'scalar') {
    base = scalarToTs(field.type)
  } else if (field.kind === 'enum' || field.kind === 'object') {
    base = field.type
  } else {
    base = 'unknown'
  }

  return field.isList ? `${base}[]` : base
}

function isOptionalProp(field: DMMF.Field): boolean {
  // Relation fields are always optional — they represent loaded associations,
  // not columns present on every row.
  return field.kind === 'object' || !field.isRequired
}

function renderField(field: DMMF.Field): string {
  const opt = isOptionalProp(field) ? '?' : ''
  return `  ${field.name}${opt}: ${fieldTsType(field)}`
}

function idFieldNames(model: DMMF.Model): string[] {
  return model.fields.filter((f) => f.isId).map((f) => f.name)
}

function uniqueScalarFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => (f.isId || f.isUnique) && f.kind === 'scalar')
}

/**
 * Returns the TypeScript source for `interfaces.ts` — model interfaces,
 * enum union types, and the helper input types used by CRUD operations.
 */
export function renderInterfaces(dmmf: DMMF.Document): string {
  const lines: string[] = [
    '// This file is auto-generated by @prisma/rest-client-generator. Do not edit manually.',
    '',
  ]

  for (const e of dmmf.datamodel.enums) {
    const values = e.values.map((v) => `'${v.name}'`).join(' | ')
    lines.push(`export type ${e.name} = ${values}`, '')
  }

  for (const model of dmmf.datamodel.models) {
    lines.push(`export interface ${model.name} {`)
    for (const field of model.fields) {
      lines.push(renderField(field))
    }
    lines.push('}', '')

    const unique = uniqueScalarFields(model)
    if (unique.length > 0) {
      lines.push(`export interface ${model.name}WhereUniqueInput {`)
      for (const field of unique) {
        lines.push(`  ${field.name}?: ${fieldTsType(field)}`)
      }
      lines.push('}', '')
    }

    const idNames = idFieldNames(model)
    if (idNames.length > 0) {
      const omitKeys = idNames.map((n) => `'${n}'`).join(' | ')
      lines.push(`export type ${model.name}CreateInput = Omit<${model.name}, ${omitKeys}>`, '')
      lines.push(`export type ${model.name}UpdateInput = Partial<Omit<${model.name}, ${omitKeys}>>`, '')
    } else {
      lines.push(`export type ${model.name}CreateInput = ${model.name}`, '')
      lines.push(`export type ${model.name}UpdateInput = Partial<${model.name}>`, '')
    }
  }

  return lines.join('\n')
}

export async function generateInterfaces(outputDir: string, dmmf: DMMF.Document): Promise<void> {
  await fs.writeFile(path.join(outputDir, 'interfaces.ts'), renderInterfaces(dmmf), 'utf-8')
}

