import type * as DMMF from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { renderIndex } from './generate-index'
import { renderInterfaces } from './generate-interfaces'
import { renderModelClient } from './generate-model-client'
import { renderRestClient } from './generate-rest-client'
import { scalarToTs } from './scalar-map'
import { toCamelCase, toKebabCase } from './utils'

// ---------------------------------------------------------------------------
// Minimal DMMF fixtures
// ---------------------------------------------------------------------------

function makeField(overrides: Partial<DMMF.Field> & Pick<DMMF.Field, 'name' | 'type'>): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
    makeField({ name: 'email', type: 'String', isUnique: true }),
    makeField({ name: 'name', type: 'String', isRequired: false }),
    makeField({ name: 'role', type: 'Role', kind: 'enum' }),
    makeField({
      name: 'posts',
      type: 'Post',
      kind: 'object',
      isList: true,
      isRequired: false,
      relationName: 'UserPosts',
      relationFromFields: [],
      relationToFields: [],
    }),
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

const postModel: DMMF.Model = {
  name: 'BlogPost',
  dbName: null,
  schema: null,
  fields: [
    makeField({ name: 'id', type: 'String', isId: true }),
    makeField({ name: 'title', type: 'String' }),
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

const mockDmmf = {
  datamodel: {
    models: [userModel, postModel],
    enums: [
      {
        name: 'Role',
        values: [
          { name: 'ADMIN', dbName: null },
          { name: 'USER', dbName: null },
        ],
      },
    ],
    types: [],
    indexes: [],
  },
} as unknown as DMMF.Document

// ---------------------------------------------------------------------------
// scalar-map
// ---------------------------------------------------------------------------

describe('scalarToTs', () => {
  it('maps known Prisma scalars to TypeScript types', () => {
    expect(scalarToTs('String')).toBe('string')
    expect(scalarToTs('Int')).toBe('number')
    expect(scalarToTs('Float')).toBe('number')
    expect(scalarToTs('Boolean')).toBe('boolean')
    expect(scalarToTs('DateTime')).toBe('Date')
    expect(scalarToTs('BigInt')).toBe('bigint')
    expect(scalarToTs('Decimal')).toBe('number')
    expect(scalarToTs('Bytes')).toBe('Uint8Array')
    expect(scalarToTs('Json')).toBe('unknown')
  })

  it('returns unknown for unrecognised types', () => {
    expect(scalarToTs('SomeNativeType')).toBe('unknown')
  })
})

// ---------------------------------------------------------------------------
// utils
// ---------------------------------------------------------------------------

describe('toKebabCase', () => {
  it('lowercases a single-word name', () => {
    expect(toKebabCase('User')).toBe('user')
  })

  it('inserts dashes at PascalCase boundaries', () => {
    expect(toKebabCase('UserProfile')).toBe('user-profile')
    expect(toKebabCase('BlogPost')).toBe('blog-post')
  })
})

describe('toCamelCase', () => {
  it('lowercases the first character', () => {
    expect(toCamelCase('User')).toBe('user')
    expect(toCamelCase('BlogPost')).toBe('blogPost')
  })
})

// ---------------------------------------------------------------------------
// generate-interfaces
// ---------------------------------------------------------------------------

describe('renderInterfaces', () => {
  it('emits enum union types', () => {
    const output = renderInterfaces(mockDmmf)
    expect(output).toContain("export type Role = 'ADMIN' | 'USER'")
  })

  it('emits a model interface with correct field types', () => {
    const output = renderInterfaces(mockDmmf)
    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: number')
    expect(output).toContain('  email: string')
  })

  it('marks optional scalar fields with ?', () => {
    const output = renderInterfaces(mockDmmf)
    expect(output).toContain('  name?: string')
  })

  it('marks relation fields as optional arrays', () => {
    const output = renderInterfaces(mockDmmf)
    expect(output).toContain('  posts?: Post[]')
  })

  it('emits WhereUniqueInput for models with id/unique fields', () => {
    const output = renderInterfaces(mockDmmf)
    expect(output).toContain('export interface UserWhereUniqueInput {')
    expect(output).toContain('  id?: number')
    expect(output).toContain('  email?: string')
  })

  it('emits CreateInput omitting the id field', () => {
    const output = renderInterfaces(mockDmmf)
    expect(output).toContain("export type UserCreateInput = Omit<User, 'id'>")
  })

  it('emits UpdateInput as Partial<Omit<Model, id>>', () => {
    const output = renderInterfaces(mockDmmf)
    expect(output).toContain("export type UserUpdateInput = Partial<Omit<User, 'id'>>")
  })

  it('uses kebab-cased URL segments for multi-word model names', () => {
    const output = renderInterfaces(mockDmmf)
    expect(output).toContain('export interface BlogPost {')
  })
})

// ---------------------------------------------------------------------------
// generate-model-client
// ---------------------------------------------------------------------------

describe('renderModelClient', () => {
  it('uses native private field for baseUrl', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain('#baseUrl: string')
  })

  it('emits findMany with pagination params', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain('async findMany(params?: { take?: number; skip?: number }): Promise<User[]>')
    expect(output).toContain("url.searchParams.set('take', String(params.take))")
  })

  it('emits findUnique when model has unique/id fields', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User | null>')
    expect(output).toContain('if (response.status === 404) return null')
  })

  it('emits create with POST method', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(output).toContain("method: 'POST'")
  })

  it('emits update with PATCH method', () => {
    const output = renderModelClient(userModel)
    expect(output).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
