    expect(output).toContain("method: 'DELETE'")
  })

  it('uses kebab-case URL segment for multi-word model name', () => {
    const output = renderModelClient(postModel)
    expect(output).toContain('`${this.#baseUrl}/blog-post`')
  })
})

// ---------------------------------------------------------------------------
