  it('imports each model client', () => {
    const output = renderRestClient(mockDmmf.datamodel.models)
    expect(output).toContain("import { UserClient } from './user-client'")
    expect(output).toContain("import { BlogPostClient } from './blog-post-client'")
  })

  it('declares camelCase readonly properties for each model', () => {
    const output = renderRestClient(mockDmmf.datamodel.models)
    expect(output).toContain('readonly user: UserClient')
    expect(output).toContain('readonly blogPost: BlogPostClient')
  })

  it('instantiates each model client in the constructor', () => {
    const output = renderRestClient(mockDmmf.datamodel.models)
    expect(output).toContain('this.user = new UserClient(baseUrl)')
    expect(output).toContain('this.blogPost = new BlogPostClient(baseUrl)')
  })
})

// ---------------------------------------------------------------------------
// generate-index
// ---------------------------------------------------------------------------

describe('renderIndex', () => {
  it('re-exports RestClient and interfaces', () => {
    const output = renderIndex(mockDmmf.datamodel.models)
    expect(output).toContain("export { RestClient } from './client'")
    expect(output).toContain("export * from './interfaces'")
  })

  it('re-exports each model client class', () => {
    const output = renderIndex(mockDmmf.datamodel.models)
